SELECT [Ship-to Address].[Customer No_], [Ship-to Address].Code, [Ship-to Address].Name, Len([Ship-to Address.name]) AS t1, [Ship-to Address].Address, Len([Ship-to Address.address]) AS t3, [Ship-to Address].[Address 2], Len([Ship-to Address.address 2]) AS t4, [Ship-to Address].City, Len([Ship-to Address.city]) AS t5, Customer.Placeholder, [Sales Header].[selling season code]
FROM ([Sales Header] INNER JOIN [Ship-to Address] ON ([Sales Header].[Ship-to Code] = [Ship-to Address].Code) AND ([Sales Header].[Sell-to Customer No_] = [Ship-to Address].[Customer No_])) INNER JOIN Customer ON [Ship-to Address].[Customer No_] = Customer.No_
GROUP BY [Ship-to Address].[Customer No_], [Ship-to Address].Code, [Ship-to Address].Name, Len([Ship-to Address.name]), [Ship-to Address].Address, Len([Ship-to Address.address]), [Ship-to Address].[Address 2], Len([Ship-to Address.address 2]), [Ship-to Address].City, Len([Ship-to Address.city]), Customer.Placeholder, [Sales Header].[selling season code]
HAVING (((Len([Ship-to Address.name]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([Ship-to Address.address]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([Ship-to Address.address 2]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione])) OR (((Len([Ship-to Address.city]))>30) AND ((Customer.Placeholder)=False) AND (([Sales Header].[selling season code])=[FiltroStagione]));

